	private static boolean hasOffsetTimezone(String label) {
		int offsetStart = label.length() - 6;
		if (offsetStart < 0) {
			return false;
		}
		char sign = label.charAt(offsetStart);
		return (sign == '+' || sign == '-')
				&& Character.isDigit(label.charAt(offsetStart + 1))
				&& Character.isDigit(label.charAt(offsetStart + 2))
				&& label.charAt(offsetStart + 3) == ':'
				&& Character.isDigit(label.charAt(offsetStart + 4))
				&& Character.isDigit(label.charAt(offsetStart + 5));
	}

